// The debounce function delays the execution of a function for a specified amount of time, preventing it from being called too frequently.

function debounce(func, wait) {
  let timeout;
  return function(...args) {
    clearTimeout(timeout);
    timeout = setTimeout(() => { func.apply(this, args); }, wait);
  }
}

// Example usage:
const sayHello = debounce(function() {
  console.log("Hello!");
}, 500);

// Call the function every 200ms for 3 seconds
for (let i = 0; i < 6; i++) {
  sayHello();
  await new Promise(resolve => setTimeout(resolve, 200));
}
